from math import gcd
from functools import reduce
from typing import List

class Solution:
    def maxGCDScore(self, nums: List[int], k: int) -> int:
        def get_gcd(arr):
            return reduce(gcd, arr)

        max_score = 0
        for i in range(len(nums)):
            for j in range(i, len(nums)):
                subarray = nums[i:j+1]
                for mask in range(1 << len(subarray)):
                    new_subarray = subarray[:]
                    ops_used = 0
                    for idx in range(len(subarray)):
                        if (mask & (1 << idx)) and ops_used < k:
                            new_subarray[idx] *= 2
                            ops_used += 1
                    if ops_used <= k:
                        max_score = max(max_score, len(new_subarray) * get_gcd(new_subarray))
        return max_score
